// React / Next.js
client.setDataProviders({
  notification: {
    get: async ({ organizationId, notificationIds }) => {
      const results = await myBackend.fetchNotifications(organizationId, notificationIds);
      return { status: 200, data: results };
    },
    delete: async ({ notificationId, organizationId }) => {
      await myBackend.deleteNotification(organizationId, notificationId);
      return { status: 200, data: undefined };
    },
    config: {
      resolveTimeout: 30000,
      getRetryConfig: { retryCount: 2, retryDelay: 500, revertOnFailure: false },
    },
  },
});

// Key constraints:
// - Only notifications with notificationSource === 'custom' are routed through this resolver.
// - Resolution pipeline order is: notification → user → comment.
//   The user resolver runs after the notification resolver, so resolver-enriched
//   user references are available when the user resolver executes.
// - The Notification model gains isNotificationResolverUsed?: boolean,
//   which is true when a notification was enriched by this resolver.
